DROP TABLE IF EXISTS `robot_status`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `robot_status` (
  `id` int NOT NULL AUTO_INCREMENT,
  `robot_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `battery_level` int DEFAULT NULL,
  `storage_used` decimal(5,2) DEFAULT NULL,
  `storage_total` decimal(5,2) DEFAULT NULL,
  `signal_strength` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `operating_state` enum('idle','scanning','charging','error') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `latitude` decimal(10,8) DEFAULT NULL,
  `longitude` decimal(11,8) DEFAULT NULL,
  `recorded_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_robot_time` (`robot_id`,`recorded_at`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
